import sys

class Solution:
    def countHighestScoreNodes(self, parents):
        n = len(parents)
        children = [[] for _ in range(n)]
        for i in range(1, n):
            children[parents[i]].append(i)
        sys.setrecursionlimit(10000)

        def subtree_size(u):
            s = 1
            for c in children[u]:
                s += subtree_size(c)
            return s

        total = subtree_size(0)
        scores = []
        for u in range(n):
            parts = [subtree_size(c) for c in children[u]]
            if u != 0:
                parts.append(total - subtree_size(u))
            score = 1
            for p in parts:
                score *= p
            scores.append(score)
        best = max(scores)
        return scores.count(best)

