from collections import deque

class Solution:
    def countHighestScoreNodes(self, parents):
        n = len(parents)
        children = [[] for _ in range(n)]
        for i in range(1, n):
            children[parents[i]].append(i)
        size = [1] * n
        order = []
        q = deque([0])
        while q:
            u = q.popleft()
            order.append(u)
            for v in children[u]:
                q.append(v)
        for u in reversed(order):
            if u != 0:
                size[parents[u]] += size[u]
        best = 0
        count = 0
        for u in range(n):
            score = 1
            for c in children[u]:
                score *= size[c]
            if u != 0:
                score *= (n - size[u])
            if score > best:
                best = score
                count = 1
            elif score == best:
                count += 1
        return count

