var countHighestScoreNodes = function(parents) {
    const n = parents.length;
    const children = Array.from({length: n}, () => []);
    for (let i = 1; i < n; i++) children[parents[i]].push(i);
    const size = new Array(n).fill(1);
    const order = [0];
    let head = 0;
    while (head < order.length) {
        const u = order[head++];
        for (const v of children[u]) order.push(v);
    }
    for (let i = order.length - 1; i >= 0; i--) {
        const u = order[i];
        if (u !== 0) size[parents[u]] += size[u];
    }
    let best = 0, count = 0;
    for (let u = 0; u < n; u++) {
        let score = 1;
        for (const c of children[u]) score *= size[c];
        if (u !== 0) score *= (n - size[u]);
        if (score > best) {
            best = score;
            count = 1;
        } else if (score === best) {
            count++;
        }
    }
    return count;
};
